head.b:skin:
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{--bg-primary:#0a0e1a;--bg-secondary:#0f1322;--bg-card:rgba(30,35,45,0.75);--accent-primary:#06b6d4;--accent-hover:#22d3ee;--accent-gradient:linear-gradient(135deg,#00d4ff,#825aff);--text-primary:#e8f0ff;--text-body:#e0e7ff;--text-secondary:#c4d4e8;--text-muted:rgba(224,231,255,0.5);--border:rgba(255,255,255,0.06);--border-hover:rgba(6,182,212,0.3);--max-page:1200px;--max-content:800px;--sidebar-width:320px;--gap:48px}
html{scroll-behavior:smooth}
body{background:var(--bg-primary);color:var(--text-body);font-family:'Inter',-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;font-size:16px;font-weight:400;line-height:1.6;-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale}
a{color:var(--accent-primary);text-decoration:none;transition:color 0.2s ease}
a:hover{color:var(--accent-hover)}
img{max-width:100%;height:auto}
.outer-wrapper{max-width:var(--max-page);margin:0 auto;padding:0 24px}
.content-wrapper{display:flex;gap:var(--gap);padding:var(--gap) 0}
.main-content{flex:1;min-width:0}
.sidebar-wrapper{width:var(--sidebar-width);flex-shrink:0}
.header-outer{background:rgba(10,14,26,0.95);backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px);border-bottom:1px solid rgba(255,255,255,0.05);position:sticky;top:0;z-index:1000}
.header-inner{max-width:var(--max-page);margin:0 auto;padding:0 24px;display:flex;align-items:center;justify-content:space-between;height:60px}
.header-logo{display:flex;align-items:center;gap:10px}
.header-logo a{display:flex;align-items:center;gap:10px;color:#fff;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;font-size:20px;font-weight:800;letter-spacing:-0.4px}
.header-logo a:hover{color:#fff}
.header-logo svg{width:32px;height:32px;flex-shrink:0}
.header-nav{display:flex;align-items:center;gap:4px}
.header-nav a{font-size:15px;font-weight:500;color:var(--text-secondary);padding:8px 16px;border-radius:6px;transition:color 0.2s ease,background 0.2s ease}
.header-nav a:hover{color:var(--text-primary);background:rgba(255,255,255,0.05)}
.header-nav a.nav-cta{background-image:var(--accent-gradient);background-color:#00d4ff;color:#fff;font-weight:700;font-size:15px;padding:8px 20px;border-radius:6px;margin-left:8px}
.header-nav a.nav-cta:hover{opacity:0.9;color:#fff}
.hamburger-toggle{display:none}
.hamburger-label{display:none;cursor:pointer;width:32px;height:32px;position:relative;z-index:1001}
.hamburger-label span,.hamburger-label span::before,.hamburger-label span::after{display:block;width:24px;height:2px;background:var(--text-primary);position:absolute;transition:all 0.3s ease}
.hamburger-label span{top:50%;left:50%;transform:translate(-50%,-50%)}
.hamburger-label span::before{content:'';top:-7px;left:0}
.hamburger-label span::after{content:'';top:7px;left:0}
.hamburger-toggle:checked + .hamburger-label span{background:transparent}
.hamburger-toggle:checked + .hamburger-label span::before{top:0;transform:rotate(45deg)}
.hamburger-toggle:checked + .hamburger-label span::after{top:0;transform:rotate(-45deg)}
.mobile-nav{display:none}
.post-card{background:var(--bg-card);border:1px solid var(--border);border-radius:14px;padding:24px;margin-bottom:24px;transition:border-color 0.3s ease,box-shadow 0.3s ease}
.post-card:hover{border-color:var(--border-hover);box-shadow:0 0 20px rgba(6,182,212,0.05)}
.post-card .post-thumbnail{margin:-24px -24px 20px -24px;border-radius:14px 14px 0 0;overflow:hidden}
.post-card .post-thumbnail-img{background-position:center;background-repeat:no-repeat;background-size:cover;width:100%;height:300px;display:block}
.post-card .post-title{margin:0 0 8px 0}
.post-card .post-title a{font-size:24px;font-weight:600;color:var(--text-primary);line-height:1.3}
.post-card .post-title a:hover{color:var(--accent-primary)}
.post-card .post-meta{font-size:13px;font-weight:400;color:var(--text-muted);margin-bottom:12px}
.post-card .post-snippet{font-size:16px;font-weight:400;color:var(--text-secondary);line-height:1.6;margin-bottom:16px}
.post-card .read-more{font-size:14px;font-weight:500;color:var(--accent-primary)}
.post-card .read-more:hover{color:var(--accent-hover)}
.blog-pager{display:flex;justify-content:center;gap:16px;padding:24px 0}
.blog-pager a{font-size:14px;font-weight:500;color:var(--accent-primary);padding:10px 20px;border:1px solid var(--border);border-radius:8px;transition:all 0.2s ease}
.blog-pager a:hover{border-color:var(--accent-primary);background:rgba(6,182,212,0.05)}
.post-full .post-title-single{font-size:32px;font-weight:700;color:var(--text-primary);line-height:1.3;margin-bottom:12px}
.post-full .post-meta-single{font-size:13px;font-weight:400;color:var(--text-muted);margin-bottom:32px}
.post-full .post-body{font-size:16px;font-weight:400;line-height:1.7;color:var(--text-body)}
.post-body h2{font-size:24px;font-weight:600;color:var(--text-primary);margin-top:32px;margin-bottom:16px}
.post-body h3{font-size:20px;font-weight:600;color:var(--text-primary);margin-top:24px;margin-bottom:12px}
.post-body p{margin-bottom:16px}
.post-body a{color:var(--accent-primary);text-decoration:none}
.post-body a:hover{text-decoration:underline}
.post-body ul,.post-body ol{margin:16px 0;padding-left:24px}
.post-body li{margin-bottom:8px}
.post-body img{max-width:100%;height:auto;border-radius:8px;margin:24px 0;display:block}
.post-body pre,.post-body code{font-family:'Consolas','Monaco','Courier New',monospace}
.post-body pre{background:#060a14;border:1px solid var(--border);border-radius:8px;padding:16px;overflow-x:auto;margin:24px 0;font-size:14px;line-height:1.5}
.post-body code{background:rgba(255,255,255,0.05);padding:2px 6px;border-radius:4px;font-size:14px}
.post-body pre code{background:none;padding:0;border-radius:0}
.post-body blockquote{border-left:3px solid var(--accent-primary);padding-left:16px;color:var(--text-secondary);font-style:italic;margin:24px 0}
.post-body table{width:100%;border-collapse:collapse;margin:24px 0}
.post-body th,.post-body td{border:1px solid var(--border);padding:10px 14px;text-align:left}
.post-body th{background:rgba(255,255,255,0.05);font-weight:600}
.post-body hr{border:none;border-top:1px solid var(--border);margin:32px 0}
.post-nav{display:flex;justify-content:space-between;gap:16px;margin-top:48px;padding-top:24px;border-top:1px solid var(--border)}
.post-nav a{font-size:14px;font-weight:500;color:var(--accent-primary)}
.post-nav a:hover{color:var(--accent-hover)}
.comments-section{margin-top:48px;padding-top:24px;border-top:1px solid var(--border)}
.comments-section .comments-title{font-size:20px;font-weight:600;color:var(--text-primary);margin-bottom:20px}
.comment-block{background:var(--bg-card);border:1px solid var(--border);border-radius:8px;padding:16px;margin-bottom:16px}
.comment-block .comment-author{font-weight:600;color:var(--accent-primary);margin-bottom:4px}
.comment-block .comment-body{color:var(--text-secondary);font-size:15px;line-height:1.6}
.comment-block .comment-timestamp{font-size:12px;color:rgba(224,231,255,0.4);margin-top:8px}
#comments{color:var(--text-secondary)}
.comment-form iframe{width:100%;border:none}
.add-comment-link{display:inline-block;margin-top:16px;font-size:14px;font-weight:500;color:var(--accent-primary)}
.add-comment-link:hover{color:var(--accent-hover)}
.sidebar-wrapper .widget{background:var(--bg-card);border:1px solid var(--border);border-radius:14px;padding:20px;margin-bottom:20px}
.sidebar-wrapper .widget .widget-title,.sidebar-wrapper .widget h2{font-size:16px;font-weight:600;color:var(--text-primary);margin-bottom:12px}
.sidebar-wrapper .widget p,.sidebar-wrapper .widget .widget-content{font-size:14px;color:var(--text-secondary);line-height:1.6}
.sidebar-wrapper .widget a{color:var(--accent-primary)}
.sidebar-wrapper .widget a:hover{color:var(--accent-hover)}
#HTML2{border-color:var(--accent-primary)}
.widget .cloud-label-widget-content{display:flex;flex-wrap:wrap;gap:8px}
.widget .cloud-label-widget-content a{display:inline-block;background:rgba(6,182,212,0.1);color:var(--accent-primary);border-radius:16px;padding:4px 12px;font-size:13px;font-weight:500;transition:background 0.2s ease}
.widget .cloud-label-widget-content a:hover{background:rgba(6,182,212,0.2)}
.widget .label-count{display:none}
.widget .PopularPosts .item-thumbnail{display:none !important}
.widget .PopularPosts .item-title a{color:var(--text-primary);font-size:14px;font-weight:500}
.widget .PopularPosts .item-title a:hover{color:var(--accent-primary)}
.widget .PopularPosts .item-snippet{display:none}
.widget .PopularPosts ul{list-style:none;padding:0}
.widget .PopularPosts li{padding:10px 0;border-bottom:1px solid var(--border)}
.widget .PopularPosts li:last-child{border-bottom:none}
.sidebar-wrapper .widget a.cta-button,a.cta-button{display:inline-block;background-image:var(--accent-gradient);background-color:#00d4ff;color:#000 !important;font-weight:700;font-size:14px;border-radius:8px;padding:12px 24px;text-align:center;transition:opacity 0.2s ease;margin-top:12px}
.sidebar-wrapper .widget a.cta-button:hover,a.cta-button:hover{opacity:0.9;color:#000 !important}
.footer-outer{background:var(--bg-primary);border-top:1px solid var(--border)}
.footer-inner{max-width:var(--max-page);margin:0 auto;padding:48px 24px 24px 24px}
.footer-columns{display:grid;grid-template-columns:1.2fr 1fr 1fr;gap:48px;margin-bottom:32px}
.footer-col h3{font-size:14px;font-weight:600;color:var(--text-primary);margin-bottom:16px;text-transform:uppercase;letter-spacing:0.5px}
.footer-col p{font-size:13px;font-weight:300;color:var(--text-muted);line-height:1.6}
.footer-col .footer-logo{display:flex;align-items:center;gap:8px;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;font-size:18px;font-weight:800;color:#fff;letter-spacing:-0.4px;margin-bottom:8px}
.footer-col .footer-logo svg{width:24px;height:24px}
.footer-links{list-style:none;padding:0}
.footer-links li{margin-bottom:8px}
.footer-links a{font-size:13px;font-weight:400;color:var(--accent-primary)}
.footer-links a:hover{color:var(--accent-hover)}
.footer-bottom{border-top:1px solid var(--border);padding-top:20px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px}
.footer-bottom span{font-size:13px;font-weight:300;color:var(--text-muted)}
.footer-bottom a{color:var(--accent-primary)}
@media(max-width:1199px){.sidebar-wrapper{width:280px}}
@media(max-width:1023px){.content-wrapper{flex-direction:column}.sidebar-wrapper{width:100%}.footer-columns{grid-template-columns:1fr 1fr;gap:32px}}
@media(max-width:767px){.outer-wrapper{padding:0 16px}.header-inner{padding:0 16px}.hamburger-label{display:block}.header-nav{display:none}.mobile-nav{display:none;position:fixed;top:60px;left:0;right:0;bottom:0;background:var(--bg-primary);z-index:999;padding:24px;flex-direction:column;gap:4px;border-top:1px solid var(--border)}.hamburger-toggle:checked ~ .mobile-nav{display:flex}.mobile-nav a{font-size:16px;font-weight:500;color:var(--text-secondary);padding:12px 16px;border-radius:8px;transition:background 0.2s ease}.mobile-nav a:hover{background:rgba(255,255,255,0.05);color:var(--text-primary)}.mobile-nav a.nav-cta{background-image:var(--accent-gradient);background-color:#00d4ff;color:#fff;font-weight:700;text-align:center;margin-top:8px}.content-wrapper{padding:24px 0;gap:24px}.post-full .post-title-single{font-size:26px}.footer-columns{grid-template-columns:1fr;gap:24px}.footer-bottom{flex-direction:column;text-align:center}.post-nav{flex-direction:column;gap:12px}.post-card .post-thumbnail-img{height:200px}}

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;
// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }
      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }
      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };
      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };
      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;
      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };
      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }
      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };
      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };
      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//
